import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Introducing ROI Hub Beta","description":"","frontmatter":{"title":"Introducing ROI Hub Beta","slug":"introducing-roi-hub-beta"},"headers":[],"relativePath":"account-hub/introducing-roi-hub-beta.md","filePath":"account-hub/introducing-roi-hub-beta.md"}'),i={name:"account-hub/introducing-roi-hub-beta.md"};function r(s,e,u,c,d,l){return a(),o("div",null,[...e[0]||(e[0]=[n('<p>Gain return on investment (ROI) insights and monitor cost data connection statuses with this new feature. Learn more here💲</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch is excited to announce a new ROI Hub tab that will appear in the navigation under Ads in Branch. ROI Hub is a single source for unifying your cost data and revenue insights across all of your different ad partner campaigns. You will get more complete cost coverage with direct integration support with over 20 of the largest and most commonly used ad partners including Google, Meta, TikTok for Business, Snap, Pinterest, and Moloco. This gives you up-to-date and accurate data from these partners.</p><p>ROI Hub also gives you a view that lets you manage your cost data connections to help you identify any issues and resolve them quickly.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Want to request access or learn more about ROI Hub? View our guide <a href="./roi-hub.html">here</a>.</p></div>',5)])])}const m=t(i,[["render",r]]);export{p as __pageData,m as default};
